const http = require('http');
const os = require('os');

if (cluster.isPrimary) {
  // 🔹 Главный процесс
  const numCPUs = os.cpus().length;
  console.log(`Главный процесс ${process.pid}. Запускаем ${numCPUs} воркеров...`);

  // Создаём воркеров по числу ядер
  for (let i = 0; i < numCPUs; i++) {
    cluster.fork();
  }

  // Когда воркер умирает — создаём нового
  cluster.on('exit', (worker) => {
    console.log(`Воркер ${worker.process.pid} завершился. Перезапуск...`);
    cluster.fork();
  });

} else {
  // 🔹 Воркеры (обрабатывают запросы)
  http.createServer((req, res) => {
    res.end(`Ответ от воркера ${process.pid}\n`);
  }).listen(3000);

  console.log(`Воркер ${process.pid} запущен`);
}
